@ARTICLE{10.1177/10781552221090904,
	author = {Khadam S and Chu T and Deekes N and FitzGerald D and Preston A and Duncan N},
	title = {An investigation of the use of app technology to support clinical management of patients with chronic myeloid leukaemia (CML).},
	journal = {J Oncol Pharm Pract},
	year = {2023},
	abstract = {INTRODUCTION: The availability of healthcare apps to support patient self-management of various medical conditions, including cancer, has increased considerably in the past decade. However, there are limited published data on the role of apps in the management of chronic myeloid leukaemia (CML). The primary aim of this study was to investigate the current and future role of apps as a means of supporting patients with CML. METHODS: A 31-item questionnaire was developed and distributed to patients via three on-line CML support groups. RESULTS: Responses were received from 286 patients. There was an approximate 2:1 female: male split and the majority (54%, n = 155) resided in the United Kingdom. 91% (n = 260) of respondents were currently receiving drug treatment for their CML. 23.4% (n = 67) of respondents were aware that apps were available to support their CML management and 11.5% (n = 33) had experience of using such an app. 94.1% (n = 238) of those who had not used a patient support app in the past stated that they would consider using an app in the future to help manage their disease. App awareness was significantly higher amongst male patients (30.3% vs. 19.9%). Likelihood of being a current or previous app user was higher amongst younger patients (16.3% for <55 years old vs. 5.6% for ≥55 years old) whilst younger patients and those with a more recent diagnosis of CML were both more likely to be interested in using an app in the future. When asked about potential app functionality, a drug interaction checker was the feature of greatest interest to respondents. CONCLUSIONS: We have identified both a lack of awareness of and a low uptake of patient support apps amongst CML patients. Importantly, we have demonstrated a clear interest in CML-specific apps amongst this population. Based on the functionality that study participants were most interested in, we will work with health care professionals, app developers and patients to develop a new app to deliver holistic support to CML patients.},
	doi = {10.1177/10781552221090904},
	pmid = {35404173 [Indexed for MEDLINE]},
	note = {PMC10302356}
}

@ARTICLE{10.1016/j.jval.2022.01.023,
	author = {Wujcik D and Dudley WN and Dudley M and Gupta V and Brant J},
	title = {Electronic Patient Symptom Management Program to Support Patients Receiving Cancer Treatment at Home During the COVID-19 Pandemic.},
	journal = {Value Health},
	year = {2022},
	abstract = {OBJECTIVES: Remote patient monitoring became critical for patients receiving cancer treatment during the COVID-19 pandemic. We sought to test feasibility of an electronic patient symptom management program implemented during a pandemic. We collected and analyzed the real-world data to inform practice quality improvement and understand the patient experience. METHODS: Eligible patients had breast, lung, or ovarian cancers, multiple myeloma, or acute myeloid leukemia and 12 weeks of planned chemotherapy. Patients were notified that a symptom survey with common symptoms derived from the National Cancer Institute's Patient-Reported Outcomes Version of the Common Terminology Criteria for Adverse Events was available to complete using a smart phone, tablet, or computer. Patients recorded their symptoms and results were sent to the provider. Patients received care guidelines for mild/moderate severity symptoms and a phone call from the provider for severe reports. RESULTS: A total of 282 patients generated > 119 088 data points. Patients completed 2860 of 3248 assigned surveys (88%), and 152 of 282 patients (54%) had symptom reports that generated an immediate notification to the provider. Longitudinal data were analyzed to determine whether previous reports predicted a notification alert and whether symptoms resolved after the alert was addressed. CONCLUSIONS: An electronic patient symptom management program was implemented in the midst of the COVID-19 pandemic. Enrollment of 282 patients and a high survey completion (88%) demonstrated feasibility/acceptance. Patients reported symptoms at severe levels of 54% of the time and received self-management instructions and provider phone calls that resolved or decreased the severity of the symptom. A standard approach and validated instrument provide opportunities for improving and benchmarking outcomes.},
	doi = {10.1016/j.jval.2022.01.023},
	pmid = {35339378 [Indexed for MEDLINE]},
	note = {PMC8941492}
}

@ARTICLE{10.12998/wjcc.v10.i6.1826,
	author = {Lu YY and Lu XM and Shao CY and Wang CC and Xu TT and Zhang BL},
	title = {Empathetic nursing with mindful cognitive therapy for fatigue, depression, and negative emotions in leukemia patients undergoing long-term chemotherapy.},
	journal = {World J Clin Cases},
	year = {2022},
	abstract = {BACKGROUND: Leukemia is a broad term for blood cell cancer. Leukemia is divided into acute or chronic, depending on cell differentiation. Leukemia patients are prone to adverse reactions during chemotherapy, such as anxiety, depression, and even suicide, affecting prognosis. As a nursing model developed by three well-known cognitive psychologists, empathetic nursing with mindfulness cognitive therapy (ENMCT) can effectively reduce anxiety and depression and improve the quality of life in patients with chronic disease. AIM: To explore the effect of ENMCT on cancer-induced fatigue, hope level, and negative emotions in patients with long-term leukemia chemotherapy. METHODS: A total of 103 patients with long-term leukemia chemotherapy diagnosed and treated in our hospital from July 2017 to October 2019 were enrolled and randomly assigned to observation and control groups using the random number table approach. Fifty-one patients in the control group received routine nursing, while 52 patients in the observation group received empathic nursing with mindfulness cognitive therapy. After three months of nursing care, cancer-induced fatigue was measured with the Piper Fatigue Scale (PFS), hope level with the Herth Hope Index (HHI), and negative emotion with the Hamilton Anxiety Scale (HAMA)/Hamilton Depression Scale (HAMD). Self-management (Chinese Strategies Used by People to Promote Health) was also recorded. RESULTS: The observation group's total scores in behavior, cognition, emotion, feeling, and PFS were lower than the control group after the intervention (P < 0.05). Keeping close contact with others, the attitude of taking positive actions, the attitude toward reality and future, and the total HHI score were higher in the observation group than the control group (P < 0.05). The observation group's HAMA and HAMD scores were lower than the control group (P < 0.05). The observation group's positive attitude, self-decision, and self-relief scores were greater than the control group (P < 0.05). CONCLUSION: Empathetic nursing with cognitive mindfulness therapy is beneficial in improving cancer-related fatigue, negative emotions, expectation level, and self-management ability in patients with long-term leukemia chemotherapy.},
	doi = {10.12998/wjcc.v10.i6.1826},
	pmid = {35317141},
	note = {PMC8891779}
}

@ARTICLE{10.1177/10781552211073576,
	author = {Elston Lafata J and Nguyen B and Staresinic C and Johnson M and Gratie D and Muluneh B},
	title = {Interpersonal communication-, education- and counselling-based interventions to support adherence to oral anticancer therapy: a systematic review.},
	journal = {J Oncol Pharm Pract},
	year = {2023},
	abstract = {Background. Many factors contribute to oral anti-cancer therapy adherence, including counselling and educational support. Objective. We systematically review the literature evaluating the effectiveness of interpersonal communication-, counselling- and education-based interventions on patient adherence to oral anticancer therapy. Methods. Using search terms pertaining to medication adherence, oral anticancer therapy, and communication, education, and counselling, we conducted a systematic search for full-text, original research articles prior to 3/13/20. Two reviewers independently reviewed each paper for inclusion and charted study information. Results. Twenty-four articles were included. All considered the use of oral anticancer therapy between two defined time points. Four studies also considered the length of time a patient persisted on therapy. Half (n = 12) of the studies reported a statistically significant relationship between the intervention and medication adherence, with no consistent pattern among intervention structure/content and effectiveness. Programmes offering in-person counselling and those targeting patients with chronic myeloid leukemia (CML), tended to report positive findings. Most studies faced substantial risk of bias, and only two reported using a behavioural theory to guide interventional content. Conclusions. Findings highlight the infancy of evidence base and need for rigorous and large-scale studies grounded in established behavioural theories to advance patient-targeted educational and counselling practices supporting adherence to oral anti-cancer therapy.},
	doi = {10.1177/10781552211073576},
	pmid = {35048768 [Indexed for MEDLINE]}
}

@ARTICLE{10.5737/23688076314470475,
	author = {Vinette B and Mrad H and El-Akhras A and Bilodeau K},
	title = {Synthesis of self-management strategies used by young adults who have undergone hematopoietic stem cell transplantation: A narrative review.},
	journal = {Can Oncol Nurs J},
	year = {2021},
	abstract = {Hematopoietic stem cell transplantation is frequently used to treat young adults with hematologic cancer. The treatment can cause a range of side effects that require patients to self-manage their symptoms. However, there do not seem to be any studies that review the literature on self-management strategies used by this group. The purpose of this paper is to summarize the self-management strategies used by young adults (18-39 years old) who have received a hematopoietic stem cell transplant for leukemia or lymphoma. A narrative review conducted in the CINAHL, MEDLINE and PsycINFO databases returned 11 papers. An analysis of these data shows that young adults use self-management strategies, including managing their emotions, turning to spiritual beliefs, seeking support from others and changing their behaviours. The results stress the importance of nursing care in supporting these self-management strategies used by young adults who have undergone hematopoietic stem cell transplantation.},
	doi = {10.5737/23688076314470475},
	pmid = {34786465},
	note = {PMC8565441}
}

@ARTICLE{10.3390/ijerph182111045,
	author = {Davis TC and Arnold CL and Mills G and Lesser GJ and Brown WM and Schulz R and Weaver KE and Pawloski PA},
	title = {Assessment of Oral Chemotherapy Nonadherence in Chronic Myeloid Leukemia Patients Using Brief Measures in Community Cancer Clinics: A Pilot Study.},
	journal = {Int J Environ Res Public Health},
	year = {2021},
	abstract = {The purpose of this pilot study was to assess Chronic Myeloid Leukemia (CML) patients' adherence to, beliefs about, and barriers to oral anticancer agents (OAC) using brief self-report measures in community-based cancer clinics. Patients completed a structured interview including a health literacy assessment, a Brief Medication Questionnaire, two single-item self-report adherence questions, and the Medications Adherence Reasons Scale. Of the 86 participants, 88.4% were white; 55.8% male; mean age, 58.7 years; and 22.1% had limited health literacy. Nonadherence (missing at least one dose in the last week) was reported by 18.6% of participants and associated (p < 0.003) with less-than-excellent perceived ability to take CML medications (16.3%). Black participants reported more difficulty taking CML medications than white participants (28.6% vs. 8.3%, p = 0.053). Among all participants, 43.0% reported their CML medicine was ineffective and 24.4% that taking CML pills was somewhat to very hard. The most common reasons for missing a dose were simply missed it (24.4%) and side effects (18.6%). Most patients perceived their ability to take CML medication was good to excellent, yet nearly one in five reported missing at least one dose in the last week. Brief, no-cost self-report assessments to screen CML patients' OAC adherence, barriers, and beliefs could facilitate counseling in busy community cancer clinics.},
	doi = {10.3390/ijerph182111045},
	pmid = {34769563 [Indexed for MEDLINE]},
	note = {PMC8582838}
}

@ARTICLE{10.3389/fonc.2021.701604,
	author = {Bucelli C and Fattizzo B and Cattaneo D and Giannotta JA and Barbullushi K and Pasquale R and Barozzi E and Barbanti MC and Pettine L and Rossi FG and Reda G and Cassin R and Barcellini W and Baldini L and Iurlo A},
	title = {Co-Occurrence of Myeloid and Lymphoid Neoplasms: Clinical Characterization and Impact on Outcome. A Single-Center Cohort Study.},
	abstract = {The co-occurrence of myeloid neoplasms and lymphoproliferative diseases (LPDs) has been epidemiologically described, particularly in myeloproliferative neoplasms (MPNs). However, the clinical features of these patients are poorly known. In this study, we evaluated a single-center cohort of 44 patients with a diagnosis of myeloid and LPD focusing on clinical features, therapy requirement, and outcome. The two diagnoses were concomitant in 32% of patients, while myeloid disease preceded LPD in 52% of cases (after a median of 37 months, 6-318), and LPD preceded myeloid neoplasm in 16% (after a median of 41 months, 5-242). The most prevalent LPD was non-Hodgkin lymphoma (50%), particularly lymphoplasmacytic lymphoma (54.5%), followed by chronic lymphocytic leukemia (27%), plasma cell dyscrasias (18.2%), and rarer associations such as Hodgkin lymphoma and Erdheim-Chester disease. Overall, 80% of BCR-ABL1-negative MPN patients required a myeloid-specific treatment and LPD received therapy in 45.5% of cases. Seven subjects experienced vascular events, 13 a grade >/= 3 infectious episode (9 pneumonias, 3 urinary tract infection, and 1 sepsis), and 9 developed a solid tumor. Finally, nine patients died due to solid tumor (four), leukemic progression (two), infectious complications (two), and brain bleeding (one). Longer survival was observed in younger patients (p = 0.001), with better performance status (p = 0.02) and in the presence of driver mutations (p = 0.003). Contrarily, a worse survival was significantly associated with the occurrence of infections (p < 0.0001). These data suggest that in subjects with co-occurrence of myeloid and lymphoid neoplasms, high medical surveillance for infectious complications is needed, along with patient education, since they may negatively impact outcome.},
	doi = {10.3389/fonc.2021.701604},
	pmid = {34733777},
	note = {PMC8558405}
}

@ARTICLE{10.1200/PO.21.00027,
	author = {Martin NA and Tepper JE and Giri VN and Stinchcombe TE and Cheng HH and Javle MM and Konnick EQ},
	title = {Adopting Consensus Terms for Testing in Precision Medicine.},
	journal = {JCO Precis Oncol},
	year = {2021},
	abstract = {Despite the well-understood benefits of biomarker and genetic testing in precision medicine, uptake remains low, particularly for patients with low socioeconomic status and minority ethnic backgrounds. Patients report having limited familiarity with testing terminology and may not be able to accurately explain testing's role in treatment decisions. Patient confusion and lack of understanding is exacerbated by a multiplicity of overlapping terms used in communicating about testing. A LUNGevity Foundation-led working group composed of five professional societies, 23 patient advocacy groups, and 19 industry members assessed and recommended specific terms for communicating with patients on testing for tumor characteristics and germline mutations. METHODS: Members completed a precision oncology testing framework analysis (biomarkers, germline variants, testing modalities, biospecimen, and commonly used testing terms) for nine solid tumors and blood cancers. The evaluation was segmented into terms that distinguish between somatic and germline testing. Additional data were captured in a comprehensive survey (1,650 respondents) led by FORCE (Facing Our Risk of Cancer Empowered) on patient preferences on germline testing terms. RESULTS: Thirty-three terms were noted in patient education related to biomarker, genetic, and genomic testing. Biomarker testing was selected as the preferred term for testing for somatic (acquired) alterations and other biomarkers. Genetic testing for an inherited mutation and genetic testing for inherited cancer risk were selected as the preferred terms for testing for germline variants. CONCLUSION: Democratizing comprehension about precision oncology testing through intentional use of plain language and common umbrella terminology by oncology health care providers and others in the oncology ecosystem may help improve understanding and communication, and facilitate shared decision making about the role of appropriate testing in treatment decisions and other aspects of oncology care.},
	doi = {10.1200/PO.21.00027},
	pmid = {34651094 [Indexed for MEDLINE]},
	note = {PMC8509918}
}

@ARTICLE{10.1177/23743735211034967,
	author = {Kranzler EC and Olson JS and Nichols HM and Yuen EY and McManus S and Buzaglo JS and Zaleta AK},
	title = {Patient-Reported Communication With Their Health Care Team About New Treatment Options for Chronic Lymphocytic Leukemia.},
	journal = {J Patient Exp},
	year = {2021},
	abstract = {Chronic lymphocytic leukemia (CLL) often requires consideration of multiple treatment options. Shared decision-making (SDM) is important, given the availability of increasingly novel therapies; however, patient-provider treatment conversations vary. We examined relationships between patient-provider discussions of new CLL treatment options and sociodemographic, clinical, and patient-provider communication variables among 187 CLL patients enrolled in Cancer Support Community's Cancer Experience Registry. Factors significantly associated with self-reports of whether patients' providers discussed new CLL treatment options with them were examined using χ2 tests, t tests, and hierarchical logistic regression. Fifty-eight percent of patients reported discussing new treatment options with their doctor. Patients with higher education were 3 times more likely to discuss new treatment options relative to those with lower education (OR = 3.06, P < .05). Patients who experienced a cancer recurrence were 7 times more likely to discuss new treatment options compared to those who had not (OR = 7.01, P < .05). Findings offer insights into the correlates of patient-provider discussions of new CLL treatment options. As novel therapies are incorporated into standards of care, opportunities exist for providers to improve patient care through enhanced SDM.},
	doi = {10.1177/23743735211034967},
	pmid = {34458567},
	note = {PMC8392805}
}

@ARTICLE{10.1016/j.jgo.2021.07.010,
	author = {Rosko A and Huang Y and Jones D and Presley CJ and Jaggers J and Owens R and Naughton M and Krok-Schoen JL},
	title = {Feasibility of implementing an exercise intervention in older adults with hematologic malignancy.},
	journal = {J Geriatr Oncol},
	year = {2022},
	abstract = {Older adults with Hematologic Malignancy (HM) are vulnerable to functional decline secondary to disease and treatment. Interventions for physical deconditioning, in concert with routine hematology care are limited. The feasibility of accrual, retention, and demand for an exercise intervention among a high-risk HM population was piloted. METHODS: Older adults with HM, on active treatment, with functional impairment were recruited prospectively to participate in a 6-month Otago Exercise Programme (OEP). Measures of motivation, self-efficacy, patient identified barriers to exercise, barriers to clinical trial enrollment, study satisfaction, and serious adverse events were captured. RESULTS: 63 patients were approached, 18 declined trial enrollment, 45 consented, 30 patients enrolled in the exercise program. The main barrier for trial enrollment was transportation/travel concerns (n = 15). Of the 45 consented participants, 8 (12.7%) dropped out due to clinical deterioration, 5 (7.9%) withdrew, and 2 (3.2%) were ineligible prior to exercise-intervention intiation. The median age was 75.5 years (range 62-83) with plasma cell dyscrasia (63%), non-Hodgkin lymphoma (20%) and leukemia (17%). Retention of the physical therapist (PT) led-OEP was 76.6% of patients (n = 23/30), and end-of-study retention was 66.7% (n = 20/30). Of the evaluable patients, 23/29 completed the PE-led OEP yielding a completion rate of 79%. Participants were extremely motivated (72.4%) and strongly intended (89.7%) to engage in regular physical activity. Exercising when tired increased from a median score of 50 at Visit 1 to 70 at Visit 2, but dropped significantly to 45 at Visit 3 (p < 0.001). Participants reported significantly lower self-efficacy to exercise over the next 6 months from Visit 1 to Visit 3 (p = 0.001). CONCLUSIONS: Older patients with HM had higher completion of in-person, PT-led exercise compared to at-home, independent exercise. Older adults were motivated and found the program acceptable, yet the ability to sustain a structured exercise program was challenging due to changes in health status. ClinicalTrials.gov Identifier: NCT02791737.},
	doi = {10.1016/j.jgo.2021.07.010},
	pmid = {34446377 [Indexed for MEDLINE]},
	note = {PMC8863976}
}
